flow-diagram.createChart:
{
r_design = reactFlowGanttRow(model: "row:design", label: reactFlowBorder(reactFlowPadding(reactFlowText("Design"),         all: 4)));
r_impl   = reactFlowGanttRow(model: "row:impl",   label: reactFlowBorder(reactFlowPadding(reactFlowText("Implementation"), all: 4)));
r_test   = reactFlowGanttRow(model: "row:test",   label: reactFlowBorder(reactFlowPadding(reactFlowText("Testing"),        all: 4)));

spec  = reactFlowGanttSpan(model: "task:spec",  row: $r_design, box: reactFlowBorder(reactFlowPadding(reactFlowText("Spec"),  all: 3)), start: 20454, end: 20461);
build = reactFlowGanttSpan(model: "task:build", row: $r_impl,   box: reactFlowBorder(reactFlowPadding(reactFlowText("Build"), all: 3)), start: 20461, end: 20478);
beta  = reactFlowGanttMilestone(model: "task:beta", row: $r_test, box: reactFlowBorder(reactFlowPadding(reactFlowText("Beta"), all: 3)), at: 20478);
qa    = reactFlowGanttSpan(model: "task:qa",   row: $r_test,   box: reactFlowBorder(reactFlowPadding(reactFlowText("QA"),    all: 3)), start: 20478, end: 20490);

e1 = reactFlowGanttEdge(model: "dep:spec->build", source: $spec,  sourceEndpoint: "END", target: $build, targetEndpoint: "START", enforce: "STRICT");
e2 = reactFlowGanttEdge(model: "dep:build->beta", source: $build, sourceEndpoint: "END", target: $beta,  targetEndpoint: "START", enforce: "WARN");

freeze = reactFlowGanttRangeDeco(model: "deco:freeze", from: 20485, to: 20488, color: "rgba(255,100,100,0.3)", label: reactFlowText("Freeze"));

axis = reactFlowGanttAxis(providerId: "days-since-epoch", rangeMin: 20450, rangeMax: 20495, zoom: 20);

reactFlowGantt(
	rootRows: list($r_design, $r_impl, $r_test),
	items:    list($spec, $build, $beta, $qa),
	edges:    list($e1, $e2),
	decorations: list($freeze),
	axis: $axis
)
}
